messages.content:
CLUSTER:
[
 {
  "riskId": "risk.definition-scopedown.intelligent-subset-inflation",
  "title": "The €300M base counts the non-intelligent majority of a market the venture cannot sell into",
  "narrative": "The venture sells intelligent rack PDUs, but tamBase anchors on Grand View's $2.81B 'rack PDU' figure — and Grand View itself states the NON-intelligent segment held the largest revenue share in 2025. IndexBox confirms the split is real by selling 'Rack PDUs' and 'Intelligent Rack PDUs' as separate EU reports. The scope-down chain carefully audited geography and FX but never audited product type: roughly half the €300M base is basic/metered units the product line does not address. TAM, SAM and YAM all inherit a ~2x product-scope inflation while the ledger label ('rack-PDU market, all segments/buyers') reads as if it were scope-matched.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Grand View's own segmentation of the $2.81B anchor reports the non-intelligent rack-PDU segment held the largest 2025 revenue share, while the venture's product is intelligent PDUs only",
    "refs": [
     "digest:tam-global-crosscheck#c2",
     "ledger:tamBase",
     "profile:Product"
    ]
   },
   {
    "step": "propagation",
    "text": "Independent sizings of the intelligent-only subset run $2.1B (GIA 2024) to $3.0B (MRF 2025) against $1.7–3.9B for total rack-PDU — and IndexBox maintains distinct EU reports for 'Rack PDUs' vs 'Intelligent Rack PDUs', confirming the vendor community treats them as different products with different bases",
    "refs": [
     "digest:tam-global-crosscheck#c12",
     "digest:tam-global-crosscheck#c13",
     "digest:tam-base#c14"
    ]
   },
   {
    "step": "model-impact",
    "text": "The €300M CE base carries the full-category value; the venture-relevant intelligent-only base is materially smaller, and every downstream funnel stage (SAM €165M, YAM €1.65M) inherits the inflation because serviceableFactor haircuts reach, not product scope",
    "refs": [
     "ledger:tamBase",
     "ledger:serviceableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Intelligent vs non-intelligent revenue split in the next Grand View / Mordor rack-PDU report vintage",
    "where": "Grand View Research rack-PDU report segment tables; Mordor Intelligence Intelligent PDU report",
    "threshold": "Non-intelligent still ≥45% of European revenue",
    "updates": "increases"
   },
   {
    "signal": "ASP spread between basic/metered and switched/outlet-metered SKUs on incumbent price lists",
    "where": "Vertiv Geist, Raritan/Legrand, and APC published EU price lists",
    "threshold": "Basic-unit volumes dominating distributor stock at <€500 ASP while intelligent SKUs sit >€1,500",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 },
 {
  "riskId": "risk.definition-scopedown.europe-30pct-arithmetic-ghost",
  "title": "The 'Europe ≈ 30%' hop is an inserted number; two sourced regional shares imply Europe is ≤24%",
  "narrative": "The single most load-bearing hop in tamBase — Europe's share of the global rack-PDU market — is stated by no source. Grand View publishes only NA = 38%; MarketIntelo puts Asia-Pacific at 38.2% and calls it the DOMINANT region. If both regional leaders hold ~38%, Europe plus rest-of-world share a ~24% residual, and Europe alone plausibly sits at 20–23%, not 30%. The 30% was inferred from NA's share alone, before the APAC datapoint existed in the corpus. A 7-point regional-share error moves the base ~23% by itself, and unlike the tornado's band it is a directional bias, not symmetric noise.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "No retrieved source states a Europe share of the global rack-PDU market; the chain inserts ≈30% by analogy to Grand View's NA = 38%",
    "refs": [
     "digest:tam-base#c1",
     "ledger:tamBase"
    ]
   },
   {
    "step": "propagation",
    "text": "MarketIntelo independently reports Asia-Pacific dominated the rack-PDU market with 38.2% revenue share; NA 38% + APAC 38.2% leaves ≤23.8% for Europe, MEA and LatAm combined, capping Europe well below the inserted 30%",
    "refs": [
     "digest:tam-global-crosscheck#c7",
     "digest:tam-global-crosscheck#c1"
    ]
   },
   {
    "step": "model-impact",
    "text": "tamBase is linear in the Europe-share hop: 30%→23% cuts the CE base ~23%, compounding with (not covered by) the ±20% band, and dragging SAM and YAM down proportionally",
    "refs": [
     "ledger:tamBase",
     "ledger:serviceableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Europe regional revenue share in any rack-PDU-specific report vintage",
    "where": "Grand View rack-PDU report regional segmentation; IndexBox world benchmark report vs EU report headline ratio",
    "threshold": "Europe stated or derivable at <27%",
    "updates": "increases"
   },
   {
    "signal": "EMEA vs Americas vs APAC rack-power revenue mix in incumbent disclosures",
    "where": "Vertiv 10-K segment reporting; Legrand annual report data-center line commentary",
    "threshold": "EMEA rack-power consistently <25% of global segment revenue",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 },
 {
  "riskId": "risk.definition-scopedown.stock-vs-flow-intensity-mismatch",
  "title": "tamBase apportions revenue by standing MW, but PDU revenue follows new-build flow — which is concentrating outside CE-7",
  "narrative": "The CE-7 = 39.8%-of-Europe hop divides standing colocation stock by standing stock. But rack-PDU revenue is fit-out-driven: it is earned when MW are delivered or refreshed, not while they sit installed. CBRE shows the flow concentrating away from CE: 57% of 2025's 937MW of new European supply lands in FLAPD (of which only Frankfurt and Amsterdam are CE-7), 85% of take-up is FLAPD, London alone exceeds 1GW and is Europe's largest market, and double-digit growth in secondary markets is going to Milan and Madrid — not Warsaw or Vienna. If CE-7's share of European capacity ADDITIONS is meaningfully below its 39.8% share of stock, the €300M systematically overstates where 2026 PDU purchase orders will actually be written, even if every input number is individually correct.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "European colo revenue-generating activity is flow-shaped: 937MW of new supply in 2025, 57% of it in FLAPD, and 85% of take-up in FLAPD — a distribution measurably different from the standing-stock table the CE-7 ratio is computed from",
    "refs": [
     "digest:geo-region-denominator#c6",
     "digest:geo-region-denominator#c7",
     "digest:geo-region-denominator#c9"
    ]
   },
   {
    "step": "propagation",
    "text": "London (>1GW, Europe's largest market) and Frankfurt together represent roughly half of European supply, and CBRE's tracked secondary-growth markets are Milan and Madrid — so the growth increment that a 9% CAGR is made of accrues disproportionately to non-CE-7 geographies, while CE-7's standing stock skews toward older, lower-density halls with slower PDU refresh",
    "refs": [
     "digest:geo-region-denominator#c3",
     "digest:geo-region-denominator#c8",
     "digest:geo-region-denominator#c19"
    ]
   },
   {
    "step": "model-impact",
    "text": "The 39.8% stock ratio overstates CE-7's share of near-term PDU revenue; tamBase should be read as a stock-weighted ceiling, with the flow-weighted (order-relevant) base materially lower — a bias no band edge in the tornado captures because it is a method error, not parameter noise",
    "refs": [
     "ledger:tamBase",
     "digest:geo-region-denominator#c4"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "CE-7 share of new European colocation MW delivered per quarter",
    "where": "CBRE 'Europe Data Centres Figures' quarterly PDFs (new supply by market)",
    "threshold": "CE-7 markets (Frankfurt, Amsterdam, Zurich, Warsaw, Vienna, Prague) <35% of tracked deliveries for two consecutive quarters",
    "updates": "increases"
   },
   {
    "signal": "Growth differential between CE-7 and non-CE secondary markets",
    "where": "Statista Europe colocation power by country, 2026 vintage vs 2025; CBRE secondary-markets commentary (Milan, Madrid)",
    "threshold": "Non-CE secondary markets adding MW at ≥2x the CE-7 ex-DE/NL rate",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 },
 {
  "riskId": "risk.ledger-self-audit.europe-thirty-percent-arithmetic-ghost",
  "title": "A hostile reviewer strikes the unsourced 'Europe ≈ 30%' hop and the €300M loses its floor, not just its band",
  "narrative": "The tamBase derivation looks disciplined — a refinement cycle even killed a contaminated €495M ceiling. But its load-bearing hop, 'Europe ≈ 30% of global', is an inserted analyst estimate: Grand View publishes only North America's 38% and no source in any search pass gives a Europe or CE rack-PDU figure. Worse, the global anchor itself is unsettled — same-category estimates run from $1.697B to $5.3B (QY Research $3.255B and Strategic Market Research $5.3B sit in this venture's own digest), a spread wider than the model's ±20% band. A diligence partner strikes the 30%, pairs the lowest credible global anchor with a conservative Europe share, and lands near €200M — below the band's floor — and the model has no sourced fact with which to push back. The band communicates 'we've bounded the uncertainty'; the derivation chain shows the uncertainty was never bounded, only anchored to one publisher's number times an invented ratio.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Diligence cross-references the global anchor: QY Research puts the global data-center PDU market at $3,255M while Strategic Market Research says $5.3B for rack PDUs alone and other publishers go as low as $1.7B — the primary anchor is one draw from a >2x distribution",
    "refs": [
     "digest:cust-mix#c9",
     "digest:cust-mix#c11",
     "ledger:tamBase"
    ]
   },
   {
    "step": "propagation",
    "text": "With the anchor contested, the unsourced 'Europe ≈ 30%' multiplier and the Statista-based '39.8% of Europe colo MW' CE-7 step (itself scope-inflated vs CBRE's 4,726MW top-15 Europe figure) cannot rescue the chain — every hop is either single-source or inserted",
    "refs": [
     "ledger:tamBase",
     "digest:geo-region-denominator#c5",
     "digest:geo-region-denominator#c0"
    ]
   },
   {
    "step": "model-impact",
    "text": "tamBase's effective uncertainty is wider and skewed below the stated 240–360 band; every downstream number inherits a base that cannot survive its first hostile audit, which matters most when the model is used to raise capital or justify CE manufacturing capacity",
    "refs": [
     "ledger:tamBase",
     "ledger:serviceableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "IndexBox EU rack-PDU report headline (currently paywalled) or any second Europe-scoped rack-PDU figure",
    "where": "IndexBox price list / report catalog; Omdia and Dell'Oro rack-power publication schedules",
    "threshold": "Any directly-scoped EU figure implying CE-7 <€250M",
    "updates": "increases"
   },
   {
    "signal": "Convergence or further divergence of next-vintage global rack-PDU estimates",
    "where": "Grand View, Mordor, QY Research 2026 report refreshes",
    "threshold": "Next-vintage spread across publishers remaining >1.8x",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 },
 {
  "riskId": "risk.structure-independence.stock-weighted-tam-misses-fitout-flow",
  "title": "TAM is apportioned on capacity stock, but PDU revenue follows fit-out flow — and the flow is concentrating outside CE-7",
  "narrative": "The €300M base scopes Europe down to CE-7 using 39.8% of Europe's colocation MW stock. But PDUs are bought at fit-out: revenue tracks new capacity delivered plus refresh, not standing stock. Europe's new-supply flow is heavily skewed — 57% of 2025's 937MW of new colo supply and 85% of take-up land in FLAPD, of which only Frankfurt and Amsterdam are CE-7; the UK alone (1,772MW, Europe's largest market) plus Paris, Dublin and fast-growing secondary markets like Milan and Madrid sit entirely outside the denominator's numerator. If CE-7's share of European fit-out flow is meaningfully below its 39.8% stock share, the €300M base is biased high in a way the 240–360 band — built from global-anchor and FX uncertainty — was never designed to cover.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "European new colo supply is flow-concentrated: 937MW expected in 2025, 57% of it in FLAPD, with 85% of take-up in FLAPD — only two of the five FLAPD markets (Frankfurt, Amsterdam) are inside CE-7",
    "refs": [
     "digest:geo-region-denominator#c6",
     "digest:geo-region-denominator#c7",
     "digest:geo-region-denominator#c9"
    ]
   },
   {
    "step": "propagation",
    "text": "The tamBase chain converts Europe→CE-7 using the 39.8% stock share of colo MW; but the UK (1,772MW, larger than Germany), France, Ireland and seven secondary markets exceeding 100MW are absorbing a disproportionate share of the new-build fit-outs where PDU purchase orders are generated",
    "refs": [
     "digest:geo-region-denominator#c1",
     "digest:geo-region-denominator#c19",
     "ledger:tamBase"
    ]
   },
   {
    "step": "model-impact",
    "text": "CE-7's share of European rack-PDU revenue is lower than its share of installed stock; the 39.8% apportionment hop biases the €300M base high independently of the global-anchor uncertainty the sensitivity band encodes",
    "refs": [
     "ledger:tamBase"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "CE-7 share of quarterly European new colo supply deliveries",
    "where": "CBRE 'Europe Data Centres Figures' quarterly reports (market-level MW delivered)",
    "threshold": "CE-7 (Frankfurt+Amsterdam+secondary CE) sustained below ~35% of European deliveries for 2 consecutive quarters",
    "updates": "increases"
   },
   {
    "signal": "Directly-scoped EU rack-PDU country revenue data",
    "where": "IndexBox EU Rack PDUs report country tables (the ledger's own pending source); Omdia vendor-share regional cut",
    "threshold": "CE-7 revenue share reported below 35% of Europe",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 },
 {
  "riskId": "risk.boundary-substitution.intelligent-subset-scope-mismatch",
  "title": "The venture sells intelligent PDUs; the TAM counts all rack PDUs — the category boundary mismatch is inside the model, not at its edge",
  "narrative": "Every boundary discussion has focused on excluded substitutes (busway, shelves). The unexamined boundary is in the other direction: the product is intelligent rack PDUs, but tamBase is explicitly scoped as the 'Central Europe rack-PDU market, all segments/buyers' — including basic and metered-only units the venture does not sell. IndexBox itself maintains a separate EU 'Intelligent Rack PDUs' report distinct from its 'Rack PDUs' report, i.e., the industry's own taxonomy treats these as different products. No retrieved source states the intelligent share of European rack-PDU revenue, and the 10–12% intelligent growth figure the model cites traces to a far broader power-and-cable-management report. The ±40% band prices measurement error on the whole category; it says nothing about what fraction of that category the venture can even quote into. Both errors stack.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "The product is intelligent rack PDUs while tamBase covers all rack PDUs; IndexBox sells 'Intelligent Rack PDUs' and 'Rack PDUs' as separate EU reports, confirming the vendor taxonomy splits the subset the venture sells from the category the model sized",
    "refs": [
     "profile:Product",
     "ledger:tamBase",
     "digest:tam-base#c14"
    ]
   },
   {
    "step": "propagation",
    "text": "The intelligent subset's cited 10–12% growth comes from the €8.5–9.5B EU Power-and-Cable-Management report — a category far broader than rack PDUs — and the directly-scoped rack-panel figure grows only 5–8%; no source quantifies the intelligent share of EU rack-PDU revenue, so the subset fraction is unknown and plausibly well below 1.0",
    "refs": [
     "digest:tam-base#c4",
     "digest:tam-base#c5"
    ]
   },
   {
    "step": "model-impact",
    "text": "The €300M base overstates the venture's category-true TAM by whatever revenue share basic/metered-only PDUs hold in CE; the sensitivity band (240–360) models measurement error of the full category, orthogonal to and stackable with the subset mismatch — and the one report that would resolve it sits behind a $4,000 paywall",
    "refs": [
     "ledger:tamBase",
     "digest:tam-base#c12"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Published intelligent-vs-total rack-PDU revenue split for EU or Germany",
    "where": "IndexBox EU/Germany Intelligent Rack PDUs report headlines; Omdia Rack PDU Annual Market Analysis abstract updates",
    "threshold": "Intelligent share reported below 70% of category revenue",
    "updates": "increases"
   },
   {
    "signal": "SKU mix stocked and quoted by CE distributors (basic vs metered vs switched/intelligent)",
    "where": "CE electrical/IT distributor price lists and catalogs (e.g., Rexel, Also/Ingram DC-infrastructure lines)",
    "threshold": "Basic+metered-only SKUs constituting the majority of listed rack-PDU line items",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 }
]

Every riskId must appear in exactly one group (as keepId or inside absorbs).
Emit JSON: { rationale, groups: [{keepId, absorbs: [true-duplicate riskIds, [] if none], foldedIndicators: []}] }
